// Helper function to calculate distance between two points using Haversine formula
function haversine(lat1: number, lon1: number, lat2: number, lon2: number): number {
  const R = 6371000; // Radius of Earth in meters
  const phi1 = (lat1 * Math.PI) / 180;
  const phi2 = (lat2 * Math.PI) / 180;
  const deltaPhi = ((lat2 - lat1) * Math.PI) / 180;
  const deltaLambda = ((lon2 - lon1) * Math.PI) / 180;

  const a =
    Math.sin(deltaPhi / 2) * Math.sin(deltaPhi / 2) +
    Math.cos(phi1) * Math.cos(phi2) * Math.sin(deltaLambda / 2) * Math.sin(deltaLambda / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return R * c;
}

// Compute total distance of a route
function computeDistance(coordinates: number[][]): number {
  let totalDistance = 0;
  for (let i = 0; i < coordinates.length - 1; i++) {
    const [lon1, lat1] = coordinates[i];
    const [lon2, lat2] = coordinates[i + 1];
    totalDistance += haversine(lat1, lon1, lat2, lon2);
  }
  return totalDistance;
}

// Compute bounding box for coordinates
export function computeBbox(coordinates: number[][]): { minLng: number; minLat: number; maxLng: number; maxLat: number } {
  let minLng = Infinity;
  let minLat = Infinity;
  let maxLng = -Infinity;
  let maxLat = -Infinity;

  for (const [lng, lat] of coordinates) {
    minLng = Math.min(minLng, lng);
    minLat = Math.min(minLat, lat);
    maxLng = Math.max(maxLng, lng);
    maxLat = Math.max(maxLat, lat);
  }

  return { minLng, minLat, maxLng, maxLat };
}

// Enrich routes with computed distance and duration
export function enrichColchesterRoutes(): ColchesterRouteData[] {
  return colchesterRoutesSeedData.map(route => {
    const distance = computeDistance(route.coordinates);
    const duration = Math.round(distance / 1.4); // ~5 km/h average = 1.4 m/s
    return {
      ...route,
      distance: Math.round(distance),
      duration,
    };
  });
}

